const logsSummary = $('Fetch Logs Summary').all().map(i => i.json);
const pipelineErrors = $('Fetch Pipeline Errors').all().map(i => i.json);

const criticalCount = logsSummary.filter(l => l.severity === 'critical').reduce((sum, l) => sum + (l.log_count || 0), 0);
const errorCount = logsSummary.filter(l => l.severity === 'error').reduce((sum, l) => sum + (l.log_count || 0), 0);
const warningCount = logsSummary.filter(l => l.severity === 'warning').reduce((sum, l) => sum + (l.log_count || 0), 0);

const stuckLocations = pipelineErrors.filter(e => e.entity_type === 'location').length;
const failedBusinesses = pipelineErrors.filter(e => e.entity_type === 'business').length;

let statusEmoji = '✅';
if (criticalCount > 0) statusEmoji = '🔴';
else if (errorCount > 0) statusEmoji = '🟡';

const logsTable = logsSummary.map(l => 
  `<tr><td>${l.source}</td><td>${l.severity}</td><td>${l.log_count}</td><td>${l.last_occurrence ? new Date(l.last_occurrence).toLocaleString('de-DE') : '-'}</td></tr>`
).join('');

const errorsTable = pipelineErrors.slice(0, 20).map(e =>
  `<tr><td>${e.entity_type}</td><td>${e.name}</td><td>${e.stage}</td><td>${e.retry_count}</td><td>${(e.last_error || '').substring(0, 80)}</td></tr>`
).join('');

return [{
  json: {
    statusEmoji,
    criticalCount,
    errorCount,
    warningCount,
    stuckLocations,
    failedBusinesses,
    logsTable,
    errorsTable,
    totalPipelineErrors: pipelineErrors.length
  }
}];
